mapper.select:
SELECT COUNT(*) FROM outsource_task ot
WHERE ot.deleted = 0
  AND ot.agent_company_id = #{agentCompanyId}

      AND ot.status = #{status}

SELECT ot.id AS outsource_task_id, ot.task_id AS project_task_id, t.task_name, ot.project_id, p.project_code, p.project_name, ot.agent_company_id, ac.company_name AS agent_company_name, ot.agent_engineer_id, ae.name AS agent_engineer_name, ot.status, ot.task_scope, ot.deadline, ot.submit_count, ot.create_time, CASE WHEN ot.deadline IS NOT NULL AND ot.deadline < CURDATE() AND ot.status NOT IN ('CONFIRMED', 'REJECTED') THEN 1 ELSE 0 END AS overdue FROM outsource_task ot INNER JOIN project_task t ON t.id = ot.task_id AND t.deleted = 0 INNER JOIN project p ON p.id = ot.project_id AND p.deleted = 0 LEFT JOIN agent_company ac ON ac.id = ot.agent_company_id AND ac.deleted = 0 LEFT JOIN agent_engineer ae ON ae.id = ot.agent_engineer_id AND ae.deleted = 0 WHERE ot.deleted = 0 AND ot.agent_company_id = #{agentCompanyId}
AND ot.status = #{status}
ORDER BY ot.create_time DESC
LIMIT #{limit}
